module top_module(div_clk,rst,time_value,contando, terminado);input div_clk; 
  input rst; 
  input contando; 
  input [3:0] time_value; 
  output reg terminado; 
  reg [3:0] countdown; 
  always @(posedge div_clk or posedge rst) 
  begin 
  if(rst) 
  begin 
  countdown <= 0; 
  terminado <= 0; 
  end 
  else 
  if(contando) 
  begin 
  if(countdown == time_value) 
  begin 
  countdown <= 0; 
  terminado <= 1; 
  end 
  else 
  begin 
  terminado <= 0; 
  countdown <= countdown + 1; 
  end 
  end 
  else 
  terminado <= 0; 
  end 
 endmodule
